import { afterEach, describe, expect, it, vi } from "vitest";
import { checkForUpdate, formatStaleMessage } from "./updates.js";
// Minimal platform: checkForUpdate only reads repo, remotePackageJsonPath,
// supportsAutoUpdate, marketplaceName, and updateHint.
const platform = {
    repo: "Project-White-Rabbit/bitfab-claude-plugin",
    remotePackageJsonPath: "package.json",
    supportsAutoUpdate: false,
    marketplaceName: "bitfab",
    updateHint: "/bitfab:update",
};
const PKG_URL = "https://raw.githubusercontent.com/Project-White-Rabbit/bitfab-claude-plugin/main/package.json";
const BUILDINFO_URL = "https://raw.githubusercontent.com/Project-White-Rabbit/bitfab-claude-plugin/main/dist/buildInfo.json";
function mockFetch(responses) {
    vi.stubGlobal("fetch", (url) => {
        const body = responses[url];
        if (body === undefined || body === null) {
            return Promise.resolve({ ok: false, json: () => Promise.reject() });
        }
        return Promise.resolve({ ok: true, json: () => Promise.resolve(body) });
    });
}
afterEach(() => {
    vi.unstubAllGlobals();
});
describe("checkForUpdate - version bump", () => {
    it("flags an update when a newer version is published", async () => {
        mockFetch({ [PKG_URL]: { version: "0.6.80" } });
        const r = await checkForUpdate("0.6.75", platform);
        expect(r.updateAvailable).toBe(true);
        expect(r.staleSameVersion).toBe(false);
        expect(r.latest).toBe("0.6.80");
    });
    it("does not flag when the installed version is current", async () => {
        mockFetch({ [PKG_URL]: { version: "0.6.75" } });
        const r = await checkForUpdate("0.6.75", platform);
        expect(r.updateAvailable).toBe(false);
        expect(r.staleSameVersion).toBe(false);
    });
});
describe("checkForUpdate - same-version staleness (the stale-cache bug)", () => {
    it("flags staleSameVersion when the published build moved on under the same version", async () => {
        mockFetch({
            [PKG_URL]: { version: "0.6.75" },
            [BUILDINFO_URL]: { gitSha: "newsha999" },
        });
        const r = await checkForUpdate("0.6.75", platform, "oldsha111");
        expect(r.staleSameVersion).toBe(true);
        expect(r.updateAvailable).toBe(true);
    });
    it("does not flag when the local build matches the published build", async () => {
        mockFetch({
            [PKG_URL]: { version: "0.6.75" },
            [BUILDINFO_URL]: { gitSha: "samesha" },
        });
        const r = await checkForUpdate("0.6.75", platform, "samesha");
        expect(r.staleSameVersion).toBe(false);
        expect(r.updateAvailable).toBe(false);
    });
    it("skips the staleness check when no local build sha is known", async () => {
        // No buildInfo URL mocked: if it were fetched the test would still pass,
        // but staleSameVersion must stay false without a local sha to compare.
        mockFetch({ [PKG_URL]: { version: "0.6.75" } });
        const r = await checkForUpdate("0.6.75", platform);
        expect(r.staleSameVersion).toBe(false);
    });
    it("does not flag staleness when the published buildInfo is absent (older release)", async () => {
        mockFetch({ [PKG_URL]: { version: "0.6.75" }, [BUILDINFO_URL]: null });
        const r = await checkForUpdate("0.6.75", platform, "oldsha111");
        expect(r.staleSameVersion).toBe(false);
        expect(r.updateAvailable).toBe(false);
    });
    it("prefers the version-bump signal over a staleness check", async () => {
        mockFetch({
            [PKG_URL]: { version: "0.6.80" },
            [BUILDINFO_URL]: { gitSha: "newsha999" },
        });
        const r = await checkForUpdate("0.6.75", platform, "oldsha111");
        expect(r.updateAvailable).toBe(true);
        expect(r.staleSameVersion).toBe(false);
    });
});
describe("formatStaleMessage", () => {
    it("points at the update hint without naming a higher version", () => {
        expect(formatStaleMessage(platform)).toContain("/bitfab:update");
        expect(formatStaleMessage(platform)).toContain("cached build is behind");
    });
});
